SELECT app_name, created_date
FROM applications
WHERE owner = 'John Doe';

SELECT COUNT(*)
FROM system_configurations
WHERE config_key = 'log_level' AND config_value = 'DEBUG';

SELECT app_name 
FROM applications 
WHERE app_id IN (SELECT app_id FROM subroutines);

SELECT subroutine_name, full_path
FROM subroutines
WHERE last_updated > '2023-09-15';
